judgeConfig.referenceSolution:
/* styles.css */
#sidebar {
    position: fixed;
    top: 0;
    left: 0;
    height: 100vh;
    width: 16rem;
    background: #e5e7eb;
    transform: translateX(-100%);
    transition: transform 0.3s ease-in-out;
}
#sidebar-toggle:checked ~ #sidebar {
    transform: translateX(0);
}
@media (min-width: 1024px) {
    #sidebar {
        position: static;
        transform: none;
    }
    #hamburger-btn {
        display: none;
    }
}
